DECLARE

BEGIN
  DELETE FROM PCRESTRICAOAVANCADACONFIG WHERE CODCONFIG IN(69, 88, 89, 90, 91, 92, 93, 94, 95);

  MERGE INTO PCRESTRICAOAVANCADACONFIG tgt
  USING (
    SELECT 1 AS CODCONFIG
         , 'PCPRODUT' AS TABELA
         , 'CODPROD' AS CAMPO
         , 'NUMBER' AS TIPOCAMPO
         , 'Produto' AS NOMELIVRE
         , 'N' AS VISIVELFILTRO
         , 'PCPRODUT' AS TABELAPESQUISA
         , 'CODPROD' AS CAMPOPESQUISA
         , 'DESCRICAO' AS DESCRICAOPESQUISA
         , NULL AS CODROTULO
         , 'S' AS CONDICAO
         , 'S' AS REGRAEXCECAO
         , 'Produto' AS GRUPO
         , 'CODPROD' AS NOMEPARAMETRO
         , 1 AS CODIGONIVEL
         , 'I' AS TIPOVALIDACAO
         , NULL AS CHAVEMULTIPLA
      FROM DUAL UNION ALL
    SELECT 2, 'PCPRODUT', 'CODFORNEC', 'NUMBER', 'Fornecedor', 'N', 'PCFORNEC', 'CODFORNEC', 'FORNECEDOR', NULL, 'S', 'S', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
    SELECT 3, 'PCPRODUT', 'CODEPTO', 'NUMBER', 'Departamento', 'N', 'PCDEPTO', 'CODEPTO', 'DESCRICAO', NULL, 'S', 'S', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
