    SELECT 5, 'PCPRODUT', 'CODCATEGORIA', 'NUMBER', 'Categoria', 'N', 'PCCATEGORIA', 'CODCATEGORIA', 'CATEGORIA', NULL, 'N', 'N', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
