    SELECT 9, 'PCPRODUT', 'CODPRODPRINC', 'NUMBER', 'Produto Principal', 'N', 'PCPRODUT', 'CODPROD', 'DESCRICAO', NULL, 'N', 'N', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
    SELECT 10, 'PCPRODUT', 'CLASSEVENDA', 'VARCHAR2', 'Classe de Venda (Produto)', 'N', NULL, NULL, NULL, NULL, 'N', 'N', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
    SELECT 11, 'PCPRODUT', 'TIPOESTOQUE', 'VARCHAR2', 'Tipo de Estoque', 'N', NULL, NULL, NULL, 'TIPOESTOQUE', 'N', 'N', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
