    SELECT 24, 'PCPRODUT', 'RETINOICO', 'VARCHAR2', 'Retinóico', 'N', NULL, NULL, NULL, 'RETINOICO', 'N', 'N', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
    SELECT 25, 'PCPRODUT', 'FARMACIAPOPULAR', 'VARCHAR2', 'Produto Farmácia Popular?', 'N', NULL, NULL, NULL, 'FARMACIAPOPULAR', 'N', 'N', 'Produto', 'CODPROD', 1, 'I', NULL FROM DUAL UNION ALL
