    SELECT 37, 'PCCLIENT', 'CODCONDCOMERCIAL', 'VARCHAR2', 'Condição Comercial (Indústria)', 'N', NULL, NULL, NULL, NULL, 'N', 'N', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
    SELECT 38, 'PCCLIENT', 'CODPRACA', 'NUMBER', 'Praça', 'N', 'PCPRACA', 'CODPRACA', 'PRACA', NULL, 'S', 'S', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
