    SELECT 52, 'PCCLIENT', 'DTVENCSUFRAMA', 'DATE', 'Dt. Venc. Suframa', 'N', NULL, NULL, NULL, NULL, 'N', 'N', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
    SELECT 53, 'PCCLIENT', 'ESTENT', 'VARCHAR2', 'UF do Estado', 'N', 'PCESTADO', 'UF', 'ESTADO', NULL, 'N', 'N', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
    SELECT 54, 'PCCLIENT', 'ORGAOPUB', 'VARCHAR2', 'Orgão Público Estadual?', 'N', NULL, NULL, NULL, 'SIMNAO', 'N', 'N', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
    SELECT 55, 'PCCLIENT', 'ORGAOPUBFEDERAL', 'VARCHAR2', 'Orgão Público Federal?', 'N', NULL, NULL, NULL, 'SIMNAO', 'N', 'N', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
    SELECT 56, 'PCCLIENT', 'ORGAOPUBMUNICIPAL', 'VARCHAR2', 'Orgão Público Municipal?', 'N', NULL, NULL, NULL, 'SIMNAO', 'N', 'N', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
