    SELECT 58, 'PCCLIENT', 'TIPOEMPRESA', 'VARCHAR2', 'Tipo de Empresa', 'N', NULL, NULL, NULL, 'TIPOEMPRESA', 'N', 'N', 'Cliente', 'CODCLI', 30, 'I', NULL FROM DUAL UNION ALL
